#include<bits/stdc++.h>
using namespace std;
long long jc[10000010],ny[10000010];
long long n,m,k;
const long long mod=998244353;
long long fastpow(long long x,long long y)
{
	long long ans=1;
	while(y)
	{
		if(y&1)
		{
			ans=ans*x%mod;
		}
		x=x*x%mod;
		y>>=1;
	}
	return ans;
}
int main()
{
	jc[0]=ny[0]=1;
	for(long long i=1;i<=10000000;i++)
	{
		jc[i]=jc[i-1]*i%mod;
	}
	ny[10000000]=fastpow(jc[10000000],mod-2);
	for(long long i=9999999;i>=1;i--)
	{
		ny[i]=ny[i+1]*(i+1)%mod;
	}
	long long t;
	scanf("%lld",&t);
	while(t--)
	{
		scanf("%lld%lld%lld",&n,&m,&k);
        if(m==0)
        {
            printf("%lld\n",jc[n]*k%mod);
            continue;
        }
		long long cnt=0;
		for(long long i=1;i*i<=m;i++)
		{
			if(m%i==0)
			{
				if(i<=n)
				{
					cnt++;
				}
				if(i*i==m)
				{
					continue;
				}
				i=m/i;
				if(i<=n)
				{
					cnt++;
				}
				i=m/i;
			}
		}
		long long a=cnt*jc[n-1]%mod;
        long long sum=((n+1)*n/2%mod-k+mod)%mod;
		long long ans=k*jc[n-1]%mod*cnt%mod+sum*jc[n-2]%mod*(n-cnt)%mod;
		ans=(ans%mod+mod)%mod;
		printf("%lld\n",ans);
	}
	return 0;
}
